/**
 * Generate Slack Webhook firewall config.
 *
 * Slack Incoming Webhooks use a URL that embeds credentials in the path:
 *   https://hooks.slack.com/services/{team_id}/{bot_id}/{token}
 *
 * Uses auth.base for URL rewriting — agent sends to a placeholder
 * host, mitmproxy rewrites to the real webhook URL.
 */

import { FIREWALL_PLACEHOLDER_HOST, writeOutput } from "./codegen";

const PLACEHOLDER_BASE = `https://${FIREWALL_PLACEHOLDER_HOST}/slack-webhook/hook`;

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated firewall config for Slack Webhook.",
    "// Webhook URL contains credentials in the path — uses auth.base for URL rewriting.",
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:slack-webhook",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const slackWebhookFirewall = {",
    '  name: "slack-webhook",',
    '  description: "Slack Webhook",',
    "  placeholders: {",
    `    SLACK_WEBHOOK_URL: "${PLACEHOLDER_BASE}",`,
    "  },",
    "  apis: [",
    "    {",
    `      base: "${PLACEHOLDER_BASE}",`,
    "      auth: {",
    '        base: "${{ secrets.SLACK_WEBHOOK_URL }}",',
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Slack Webhook firewall config...");
  const ts = generateTypeScript();
  writeOutput("slack-webhook", ts, import.meta.dirname);
}
